LAYER
	NAME "poligonos"
	GROUP "STT"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	#HEADER "plantillas/inicio.html"
	TEMPLATE "plantillas/stt/poligonos.html"	
	#FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, dep, prov, dist, com_camp, sector, cod_pred, UPPER(poses) AS titular, dni, ha || ' ha.' AS super_perim, geom FROM geo.poligonos_pp) as stt using unique gid using srid=32719"
	INCLUDE "configuracion/postgresql_stt.map"
	PROJECTION
		"init=epsg:32719"
	END
	CLASSITEM "gid"	
	METADATA
		"wms_group_title" "STT"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Poligonos"
		"wms_abstract" "Poligonos :: Perú"
		"wms_credit" "STT"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"autor" ""
		"wms_extent" "253857.8210503729 8341444.2566 259433.1579 8346629.686000002"
		"wms_srs" "EPSG:32719"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
	END
	CLASS
		NAME "Polígono"
		EXPRESSION /./
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 0 0 255
			WIDTH 2
		END		
	END
END # Layer